package org.seqra.spring.proxy

import org.springframework.http.ResponseEntity
import org.springframework.web.bind.annotation.*

/**
 * Controller exposing URL-fetch endpoints.
 *
 * Every endpoint passes user-controlled input (URL) to [UrlFetchService.fetch]
 * without validation, creating an SSRF vulnerability.  The taint travels through
 * a Kotlin coroutine [scope.launch] dispatched on [Dispatchers.IO].
 */
@RestController
@RequestMapping("/api/proxy")
class ProxyController(private val fetchService: UrlFetchService) {

    /**
     * Fetch via JSON body — taint flows through [FetchRequest] DTO field.
     */
    @PostMapping("/fetch")
    fun fetchUrl(@RequestBody request: FetchRequest): ResponseEntity<String> {
        return try {
            val body = fetchService.fetch(request.url, request.headers)
            ResponseEntity.ok(body)
        } catch (e: Exception) {
            ResponseEntity.badRequest().body("Fetch failed: ${e.message}")
        }
    }

    /**
     * Fetch via query parameter — taint flows directly from request param.
     */
    @GetMapping("/fetch")
    fun fetchByParam(@RequestParam url: String): ResponseEntity<String> {
        return try {
            val body = fetchService.fetch(url)
            ResponseEntity.ok(body)
        } catch (e: Exception) {
            ResponseEntity.badRequest().body("Fetch failed: ${e.message}")
        }
    }
}

package org.seqra.spring.proxy

import kotlinx.coroutines.CompletableDeferred
import kotlinx.coroutines.CoroutineScope
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.launch
import org.springframework.stereotype.Service
import java.io.BufferedReader
import java.io.InputStreamReader
import java.net.URI

/**
 * Service that fetches content from a user-supplied URL using Kotlin coroutines.
 *
 * Vulnerability: SSRF — the caller-provided URL is passed directly to [java.net.URL.openConnection]
 * without any validation or allow-list check, letting an attacker reach internal
 * services (e.g. cloud metadata endpoints, internal APIs).
 */
@Service
class UrlFetchService {

    private val scope = CoroutineScope(Dispatchers.IO)

    /**
     * Fetches the content at [url] by launching a coroutine on [scope].
     * No URL validation is performed — intentionally vulnerable.
     */
    fun fetch(url: String, headers: Map<String, String> = emptyMap()): String {
        val deferred = CompletableDeferred<String>()

        scope.launch {
            try {
                val connection = URI.create(url).toURL().openConnection()

                headers.forEach { (k, v) -> connection.setRequestProperty(k, v) }
                connection.connect()

                val body = BufferedReader(InputStreamReader(connection.getInputStream())).use { reader ->
                    reader.readText()
                }
                deferred.complete(body)
            } catch (e: Exception) {
                deferred.completeExceptionally(e)
            }
        }

        return kotlinx.coroutines.runBlocking { deferred.await() }
    }
}

