                        - pattern: MediaType.TEXT_XML_VALUE
                        - pattern: MediaType.IMAGE_PNG_VALUE
                        - pattern: MediaType.IMAGE_JPEG_VALUE
                        - pattern: MediaType.IMAGE_GIF_VALUE
          - patterns:
              - pattern-not-inside: |
                  @RequestMapping(..., produces = $CPRODUCES, ...)
                  class $CLAZZ {
                    ...
                  }
              - metavariable-pattern:
                  metavariable: $CPRODUCES
                  patterns:
                    - pattern-either:
                        - pattern: '"application/json"'
                        - pattern: '"text/plain"'
                        - pattern: '"application/pdf"'
                        - pattern: '"application/octet-stream"'
                        - pattern: '"application/xml"'
                        - pattern: '"text/xml"'
                        - pattern: '"image/png"'
                        - pattern: '"image/jpeg"'
                        - pattern: '"image/gif"'
                        - pattern: MediaType.APPLICATION_JSON_VALUE
                        - pattern: MediaType.TEXT_PLAIN_VALUE
                        - pattern: MediaType.APPLICATION_PDF_VALUE
                        - pattern: MediaType.APPLICATION_OCTET_STREAM_VALUE
                        - pattern: MediaType.APPLICATION_XML_VALUE
                        - pattern: MediaType.TEXT_XML_VALUE
                        - pattern: MediaType.IMAGE_PNG_VALUE
                        - pattern: MediaType.IMAGE_JPEG_VALUE
                        - pattern: MediaType.IMAGE_GIF_VALUE
          - focus-metavariable: $UNTRUSTED

      - patterns:
          - pattern-inside: |
              @$ANNOTATION(..., produces = $PRODUCES_HTML, ...)
              $RT $METHOD(...) { ... }
          - metavariable-pattern:
              metavariable: $PRODUCES_HTML
              patterns:
                - pattern-either:
                    - pattern: '"text/html"'
                    - pattern: '"text/html;charset=UTF-8"'
                    - pattern: '"text/html;charset=utf-8"'
                    - pattern: '"image/svg+xml"'
                    - pattern: MediaType.TEXT_HTML_VALUE
                    - pattern: MediaType.IMAGE_SVG_XML_VALUE
          - pattern: return $UNTRUSTED;
          - focus-metavariable: $UNTRUSTED

      - patterns:
          - metavariable-pattern:
              metavariable: $ANNOTATION
              patterns:
                - pattern-either:
                    - pattern: GetMapping
                    - pattern: PostMapping
                    - pattern: PutMapping
                    - pattern: PatchMapping
                    - pattern: DeleteMapping
                    - pattern: RequestMapping
          - pattern-inside: |
                @$ANNOTATION(...)
                $RETURNTYPE $METHOD(...) {
                  ...
                }
          - pattern-either:
              - pattern: return $X.contentType(MediaType.TEXT_HTML).body($UNTRUSTED);
              - pattern: return $X.contentType(MediaType.IMAGE_SVG_XML).body($UNTRUSTED);
          - focus-metavariable: $UNTRUSTED


      - patterns:
          - pattern-either:
              - pattern: |
                  (HttpServletResponse $R).setContentType("$CT_HTML");
                  ...
                  $W = (HttpServletResponse $R).getWriter(...);
                  ...
                  $W.$WRITE(..., $UNTRUSTED, ...);
              - pattern: |
                  (HttpServletResponse $R).setHeader("Content-Type", "$CT_HTML");
                  ...
                  $W = (HttpServletResponse $R).getWriter(...);
                  ...
                  $W.$WRITE(..., $UNTRUSTED, ...);
              - pattern: |
                  (HttpServletResponse $R).addHeader("Content-Type", "$CT_HTML");
                  ...
                  $W = (HttpServletResponse $R).getWriter(...);
                  ...
                  $W.$WRITE(..., $UNTRUSTED, ...);
          - metavariable-regex:
              metavariable: $CT_HTML
              regex: '^text/html(\s*;.*)?$'
          - focus-metavariable: $UNTRUSTED

rules:
  - id: groovy-injection
    severity: ERROR
    message: >-
      Potential code injection: Groovy invocation with user-controlled input.
    metadata:
      cwe:
        - CWE-94
      short-description: Found Groovy invocation with user-controlled input
      full-description: |-
        Groovy code injection occurs when untrusted input reaches Groovy evaluation APIs
        such as `GroovyShell.evaluate(...)`, `parse(...)`, or `Eval.me(...)`.

        Vulnerable example:

        ```java
        import groovy.lang.GroovyShell;

        public class ScriptService {
            public Object run(String scriptFromRequest) {
                GroovyShell shell = new GroovyShell();
                return shell.evaluate(scriptFromRequest); // VULNERABLE
            }
        }
        ```

        Safe example:

        ```java
        import groovy.lang.Binding;
        import groovy.lang.GroovyShell;

        public class ScriptService {
            public Object run(int a, int b) {
                String trustedScript = "x + y";
                Binding binding = new Binding();
                binding.setVariable("x", a);
                binding.setVariable("y", b);
                GroovyShell shell = new GroovyShell(binding);
                return shell.evaluate(trustedScript);
            }
        }
        ```

        Key vulnerable patterns covered by this rule include Groovy shell parse/evaluate APIs and `groovy.util.Eval.*`.
      references:
        - https://owasp.org/www-community/attacks/Code_Injection
      provenance: https://find-sec-bugs.github.io/bugs.htm#GROOVY_SHELL
