rules:
  - id: sql-injection
    severity: ERROR
    message: >-
      Potential SQL injection: detected unescaped input from a user-manipulated data source going into a SQL execution call or statement
    metadata:
      cwe: CWE-89
      short-description: Potential SQL injection
      full-description: |-
        SQL injection happens when untrusted data is embedded into a SQL string that is executed by a SQL execution API.
        This rule focuses on the security-sensitive call itself (for example `Statement.executeQuery(...)`, `JdbcTemplate.query(...)`,
        or `EntityManager.createNativeQuery(...)`).

        Vulnerable example:

        ```java
        import java.sql.Connection;
        import java.sql.ResultSet;
        import java.sql.Statement;

        public class UserRepository {
            public ResultSet findById(Connection conn, String userIdFromRequest) throws Exception {
                // userIdFromRequest is untrusted (source can be Servlet, Spring, etc.)
                String sql = "SELECT * FROM users WHERE id = '" + userIdFromRequest + "'";

                // VULNERABLE: tainted data reaches SQL execution API
                Statement st = conn.createStatement();
                return st.executeQuery(sql);
            }
        }
        ```

        Safe example:

        ```java
        import java.sql.Connection;
        import java.sql.PreparedStatement;
        import java.sql.ResultSet;

        public class UserRepository {
            public ResultSet findById(Connection conn, String userIdFromRequest) throws Exception {
                String sql = "SELECT * FROM users WHERE id = ?";

                PreparedStatement ps = conn.prepareStatement(sql);
                ps.setString(1, userIdFromRequest); // bound as data, not SQL syntax
                return ps.executeQuery();
            }
        }
        ```

        Key vulnerable patterns covered by this rule include JDBC statement execution, Spring JDBC operations,
        and dynamic JPA/Hibernate query creation when untrusted input controls query text.
      references:
        - https://owasp.org/www-community/attacks/SQL_Injection
        - https://en.wikipedia.org/wiki/SQL_injection
      license: LGPL 2.1 (GNU Lesser General Public License, Version 2.1)
      provenance:
        - https://find-sec-bugs.github.io/bugs.htm#SQL_INJECTION
        - https://gitlab.com/gitlab-org/security-products/sast-rules/-/blob/main/rules/lgpl-cc/java/inject/rule-SqlInjection.yml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: servlet-untrusted-data
        - rule: java/lib/spring/untrusted-data-source.yaml#spring-untrusted-data-source
          as: spring-untrusted-data
        - rule: java/lib/spring/jdbc-sqli-sinks.yaml#spring-sqli-sink
          as: sink
      on:
        - 'servlet-untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'
        - 'spring-untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

rules:
  - id: ssrf
    severity: ERROR
    message: >-
      Potential SSRF: the web server receives a URL or similar request from an upstream component and retrieves the contents of this URL,
      it does not sufficiently ensure that the request is being sent to the expected destination.
    metadata:
      cwe: CWE-918
      short-description: Potential server-side request forgery (SSRF)
      full-description: |-
        SSRF occurs when untrusted input reaches outbound network APIs without strict destination controls.
        This rule focuses on calls such as URL/URI connection methods, `RestTemplate` requests,
        socket address creation, and URL-based DB connection entrypoints.

        Vulnerable example:

        ```java
        import java.net.URL;

        public class FetchService {
            public String fetch(String targetFromRequest) throws Exception {
                // targetFromRequest is untrusted
                URL url = new URL(targetFromRequest);

                // VULNERABLE
                return new String(url.openStream().readAllBytes());
            }
        }
        ```

        Safe example:

        ```java
        import java.net.InetAddress;
        import java.net.URI;
        import java.util.Set;

        public class FetchService {
            private static final Set<String> ALLOWED_HOSTS = Set.of("api.example.com", "partner.example.com");

            public URI validate(String targetFromRequest) throws Exception {
                URI uri = new URI(targetFromRequest);
                if (!"https".equalsIgnoreCase(uri.getScheme())) {
                    throw new IllegalArgumentException("Only HTTPS allowed");
                }

                String host = uri.getHost();
                if (host == null || !ALLOWED_HOSTS.contains(host.toLowerCase())) {
                    throw new SecurityException("Host not allowed");
                }

                InetAddress addr = InetAddress.getByName(host);
                if (addr.isAnyLocalAddress() || addr.isLoopbackAddress() || addr.isSiteLocalAddress()) {
                    throw new SecurityException("Internal addresses are forbidden");
                }

                return uri;
            }
        }
        ```

        Key vulnerable patterns covered by this rule include `URL.open*`, `URI.create(...).toURL()`,
        `RestTemplate` request methods with tainted URI/string targets, and tainted socket/connection targets.
      references:
        - https://owasp.org/www-community/attacks/Server_Side_Request_Forgery
        - https://portswigger.net/web-security/ssrf
      provenance: https://gitlab.com/gitlab-org/security-products/sast-rules/-/blob/main/java/ssrf/rule-SSRF.yml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: servlet-untrusted-data
        - rule: java/lib/spring/untrusted-data-source.yaml#spring-untrusted-data-source
          as: spring-untrusted-data
        - rule: java/lib/generic/ssrf-sinks.yaml#java-ssrf-sink
          as: sink
      on:
        - 'servlet-untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'
        - 'spring-untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

  - id: java-servlet-parameter-pollution
    severity: ERROR
    message: |
      The application was found including unvalidated user input into a URL, which could lead to
      HTTP Parameter Pollution (HPP) or worse, Server Side Request Forgery (SSRF). This could
      allow an adversary to override the value of a URL or a request parameter.  HTTP Parameter
      Pollution
      (HPP) attacks consist of injecting encoded query string delimiters into other existing
      parameters. If a web
      application does not properly sanitize the user input, an adversary may modify the logic of
      these
      requests to other applications.

      To remediate this issue, never allow user input directly into creation of a URL or URL
      parameter. Consider
      using a map to look up user-supplied information and return exact values to be used in the
      generation of
      requests.

      Example using a map to look up a key to be used in a HTTP request:
      ```
      HashMap<String, String> lookupTable = new HashMap<>();
      lookupTable.put("key1", "value1");
      lookupTable.put("key2", "value2");
      String userInput = request.getParameter("key");

      // Create a CloseableHttpClient, ideally any requests issued should be done
      // out-of-band from the servlet request itself (such as using a separate thread/scheduler
      system)
      try (final CloseableHttpClient httpClient = HttpClients.createDefault()) {
          // Lookup the value from our user input from our lookupTable
          String value = lookupTable.getOrDefault(userInput, "value1");
          // Construct the url, with the hardcoded url and only pass in the value from the
      lookupTable,
          // not direct user input
          final HttpGet httpget = new HttpGet("https://example.com/getId?key="+value);
          // Execute the request
          CloseableHttpResponse clientResponse = httpClient.execute(httpget);
          // Read the response
          byte[] responseData = clientResponse.getEntity().getContent().readAllBytes();
          // Handle the response
          // ...
      }
      ```

      If using a map is not possible, the user-supplied input must be encoded prior to use, and
      never allow full
      URLs:
      ```
      // Get user input
      String userInput = request.getParameter("key");
      // Encode the string using java.net.URLEncoder with the UTF-8 character set
      String encodedString = java.net.URLEncoder.encode(userInput, StandardCharsets.UTF_8);
      // Create a CloseableHttpClient, ideally any requests issued should be done
      // out-of-band from the servlet request itself (such as using a separate thread/scheduler
      system)
      try (final CloseableHttpClient httpClient = HttpClients.createDefault()) {
        // Construct the url, with the hardcoded url and only pass in the encoded value, never a
      full URL
        final HttpGet httpget = new HttpGet("https://example.com/getId?key="+encodedString);
        // Execute the request
        CloseableHttpResponse clientResponse = httpClient.execute(httpget);
        // Read the response
        byte[] responseData = clientResponse.getEntity().getContent().readAllBytes();
        // handle the response
      }
      ```

      For more information on SSRF see OWASP:
      https://cheatsheetseries.owasp.org/cheatsheets/Server_Side_Request_Forgery_Prevention_Cheat_Sheet.html

      For more information on HTTP Parameter Pollution see:
      https://en.wikipedia.org/wiki/HTTP_parameter_pollution
    metadata:
      cwe: "CWE-88"
      short-description: "Improper neutralization of argument delimiters in a command ('Argument Injection')"
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/generic/ssrf-sinks.yaml#java-http-parameter-pollution-sinks
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

rules:
  - id: string-normalize-after-validation
    severity: WARNING
    message: >-
      The application was found matching a variable during a regular expression
      pattern match, and then calling a Unicode normalize function after validation has occurred.
      This is usually indicative of a poor input validation strategy as an adversary may attempt to
      exploit the normalization process.
    metadata:
      cwe: CWE-180
      short-description: String validate before canonicalization
      full-description: |-
        The application was found matching a variable during a regular expression
        pattern match, and then calling a Unicode normalize function after validation has occurred.
        This is usually indicative of a poor input validation strategy as an adversary may attempt to
        exploit the normalization process.

        To remediate this issue, always perform Unicode normalization before any validation of a
        string.

        Example of normalizing a string before validation:
        ```
        // User input possibly containing malicious unicode
        String userInput = "\uFE64" + "tag" + "\uFE65";
        // Normalize the input
        userInput = Normalizer.normalize(userInput, Normalizer.Form.NFKC);
        // Compile our regex pattern looking for < or > characters
        Pattern pattern = Pattern.compile("[<>]");
        // Create a matcher from the userInput
        Matcher matcher = pattern.matcher(userInput);
        // See if the matcher matches
        if (matcher.find()) {
            // It did so throw an error
            throw new Exception("found banned characters in input");
        }
        ```
      references:
        - https://wiki.sei.cmu.edu/confluence/display/java/IDS01-J.+Normalize+strings+before+validating+them
      provenance: https://gitlab.com/gitlab-org/security-products/sast-rules/-/blob/main/java/strings/rule-NormalizeAfterValidation.yml
    languages:
      - java
    patterns:
      - pattern: |
          $Y = java.util.regex.Pattern.compile("[<>]");
          ...
          $Y.matcher($VAR);
          ...
          java.text.Normalizer.normalize($VAR, ...);

  - id: format-string-external-manipulation
    severity: WARNING
    message: >-
      The application allows user input to control format string parameters. By passing invalid format
      string specifiers an adversary could cause the application to throw exceptions or possibly leak
      internal information depending on application logic.
    metadata:
      cwe: CWE-134
      short-description: Use of externally-controlled format string
      full-description: |-
        Format-string misuse occurs when untrusted data reaches a formatting API as the format template
        (for example `String.format($FORMAT, ...)`, `Formatter.format(...)`, or `printf(...)`).

        Vulnerable example:

        ```java
        public class MessageService {
            public String render(String formatFromRequest, String userValue) {
                // formatFromRequest is untrusted and controls the format string
                return String.format(formatFromRequest, userValue); // VULNERABLE
            }
        }
        ```

        Safe example:

        ```java
        public class MessageService {
            public String render(String formatFromRequest, String userValue) {
                // Keep format string constant; use untrusted data only as arguments
                return String.format("User value: %s", userValue);
            }
        }
        ```

        Key vulnerable patterns covered by this rule include `String.format`, `Formatter.format`,
        `PrintStream.printf/format`, and `System.out.printf/format` when template text is tainted.
      provenance: https://gitlab.com/gitlab-org/security-products/sast-rules/-/blob/main/java/strings/rule-FormatStringManipulation.yml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: servlet-untrusted-data
        - rule: java/lib/spring/untrusted-data-source.yaml#spring-untrusted-data-source
          as: spring-untrusted-data
        - rule: java/security/strings.yaml#java-string-format-sinks
          as: sink
      on:
        - 'servlet-untrusted-data.$UNTRUSTED -> sink.$FORMAT_STR'
        - 'spring-untrusted-data.$UNTRUSTED -> sink.$FORMAT_STR'

  - id: java-string-format-sinks
    options:
      lib: true
    severity: NOTE
    message: String formatter is obtained from untrusted data source
    metadata:
      provenance: https://gitlab.com/gitlab-org/security-products/sast-rules/-/blob/main/java/strings/rule-FormatStringManipulation.yml
    languages:
      - java
    patterns:
      - pattern-either:
          - pattern: String.format($FORMAT_STR, ...);
          - pattern: String.format((java.util.Locale $LOCALE), $FORMAT_STR, ...);
          - pattern: (java.util.Formatter $F).format($FORMAT_STR, ...);
          - pattern: (java.util.Formatter $F).format((java.util.Locale $LOCALE), $FORMAT_STR, ...);
          - pattern: (java.io.PrintStream $F).printf($FORMAT_STR, ...);
          - pattern: (java.io.PrintStream $F).printf((java.util.Locale $LOCALE), $FORMAT_STR, ...);
          - pattern: (java.io.PrintStream $F).format($FORMAT_STR, ...);
          - pattern: (java.io.PrintStream $F).format((java.util.Locale $LOCALE), $FORMAT_STR, ...);
          - pattern: System.out.printf($FORMAT_STR, ...);
          - pattern: System.out.printf((java.util.Locale $LOCALE), $FORMAT_STR, ...);
          - pattern: System.out.format($FORMAT_STR, ...);
          - pattern: System.out.format((java.util.Locale $LOCALE), $FORMAT_STR, ...);

rules:
  - id: unvalidated-redirect-in-servlet-app
    severity: WARNING
    message: >-
      Application redirects to a destination URL specified by a user-supplied
      parameter that is not validated. This could direct users to malicious locations.
      Consider using an allowlist to validate URLs.
    metadata:
      cwe:
        - CWE-601
      short-description: Application redirects to user-manipulated URL which can be malicious
      full-description: |-
        Unvalidated redirects (also called “open redirects”) occur when a web application accepts
        untrusted input that specifies a URL to redirect to, and then performs the redirect without
        sufficient validation. Attackers can exploit this to send users to malicious websites while making
        the link appear to come from a trusted domain (phishing),
        bypass intermediate access checks, or chain the redirect into broader attacks.

        Vulnerable code sample

        ```java
        // A simple Java Servlet example
        protected void doGet(HttpServletRequest request, HttpServletResponse response)
                throws ServletException, IOException {

            // "url" parameter is taken directly from user input
            String url = request.getParameter("url");

            if (url != null && !url.isEmpty()) {
                // VULNERABLE: redirects to any URL provided by the user
                response.sendRedirect(url);
            } else {
                response.sendRedirect("home.jsp");
            }
        }
        ```

        To remediate this issue, avoid redirecting to arbitrary URLs from user-controlled input.
        Prefer server-side mapping of identifiers to known-safe destinations, or strictly validate and
        restrict redirect targets (e.g., to internal paths or a small whitelist of external domains).

        More secure approach using an internal whitelist of paths:

        ```java
        // Example of safer redirect handling
        private static final Set<String> ALLOWED_TARGETS = Set.of(
            "home",
            "profile",
            "orders"
        );

        protected void doGet(HttpServletRequest request, HttpServletResponse response)
                throws ServletException, IOException {

            String target = request.getParameter("target");  // e.g., "home", "profile"
            String redirectPath = "/home.jsp";              // default safe page

            if (target != null && ALLOWED_TARGETS.contains(target)) {
                switch (target) {
                    case "home":
                        redirectPath = "/home.jsp";
                        break;
                    case "profile":
                        redirectPath = "/user/profile.jsp";
                        break;
                    case "orders":
                        redirectPath = "/orders/list.jsp";
                        break;
                }
            }

            // Only redirect to application-internal paths
            response.sendRedirect(request.getContextPath() + redirectPath);
        }
        ```

        If you must support external redirects, validate strictly that the destination is on an approved list of domains and reject all others:

        ```java
        private static final Set<String> ALLOWED_DOMAINS = Set.of("example.com", "trusted-partner.com");

        protected void doGet(HttpServletRequest request, HttpServletResponse response)
                throws ServletException, IOException {

            String url = request.getParameter("url");
            if (url == null) {
                response.sendRedirect(request.getContextPath() + "/home.jsp");
                return;
            }

            try {
                URI uri = new URI(url);

                // Require an explicit host and approved scheme
                String host = uri.getHost();
                String scheme = uri.getScheme();

                if (host != null
                        && ( "http".equalsIgnoreCase(scheme) || "https".equalsIgnoreCase(scheme) )
                        && ALLOWED_DOMAINS.contains(host.toLowerCase())) {

                    response.sendRedirect(uri.toString());
                } else {
                    // Fallback to a safe internal page
                    response.sendRedirect(request.getContextPath() + "/home.jsp");
                }
            } catch (URISyntaxException e) {
                // Invalid URL; redirect to safe internal page
                response.sendRedirect(request.getContextPath() + "/home.jsp");
            }
        }
        ```
      references:
        - https://find-sec-bugs.github.io/bugs.htm#UNVALIDATED_REDIRECT
        - https://cwe.mitre.org/data/definitions/601.html
      provenance: https://find-sec-bugs.github.io/bugs.htm#UNVALIDATED_REDIRECT
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/generic/servlet-unvalidated-redirect-sinks.yaml#java-servlet-unvalidated-redirect-sinks
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$URL'

  - id: unvalidated-redirect-in-spring-app
    severity: WARNING
    message: >-
      Application redirects to a destination URL specified by a user-supplied
      parameter that is not validated. This could direct users to malicious locations.
      Consider using an allowlist to validate URLs.
    metadata:
      cwe:
        - CWE-601
      short-description: Application redirects to user-manipulated URL which can be malicious
      full-description: |-
        Unvalidated redirects (also called “open redirects”) occur when a web application accepts untrusted input that specifies a URL to redirect to, and then performs the redirect without sufficient validation. In Spring MVC/Boot applications, this often happens when controllers return a `redirect:` view or `RedirectView` using user-supplied data. Attackers can exploit this to trick users into visiting malicious sites via URLs that appear to be from a trusted domain, or to chain redirects into other attacks.

        Vulnerable code sample

        ```java
        @Controller
        public class RedirectController {

            @GetMapping("/redirect")
            public String redirect(@RequestParam("url") String url) {
                // VULNERABLE: unvalidated user-controlled URL
                return "redirect:" + url;
            }
        }
        ```

        Or with `RedirectView`:

        ```java
        @Controller
        public class RedirectController {

            @GetMapping("/redirect")
            public RedirectView redirect(@RequestParam("url") String url) {
                // VULNERABLE: unvalidated user-controlled URL
                return new RedirectView(url);
            }
        }
        ```

        To remediate this issue, avoid redirecting to arbitrary URLs derived directly from user input. Prefer mapping short, controlled identifiers to known internal routes, or if external redirects are required, strictly validate against a whitelist of allowed hosts and schemes.

        Example: safer internal redirects using a target name instead of a full URL:

        ```java
        @Controller
        public class SafeRedirectController {

            private static final Map<String, String> ALLOWED_TARGETS = Map.of(
                "home",    "/home",
                "profile", "/user/profile",
                "orders",  "/orders/list"
            );

            @GetMapping("/redirect")
            public String redirect(
                    @RequestParam(value = "target", required = false) String target) {

                // Default safe page
                String path = ALLOWED_TARGETS.getOrDefault(target, "/home");

                // Only internal paths, no scheme/host
                return "redirect:" + path;
            }
        }
        ```

        Example: if you must support external redirects, validate against an allowlist of domains:

        ```java
        @Controller
        public class ExternalRedirectController {

            private static final Set<String> ALLOWED_DOMAINS = Set.of(
                "example.com",
                "trusted-partner.com"
            );

            @GetMapping("/external-redirect")
            public String externalRedirect(
                    @RequestParam("url") String url,
                    HttpServletRequest request) {

                try {
                    URI uri = new URI(url);
                    String host   = uri.getHost();
                    String scheme = uri.getScheme();

                    if (host != null
                            && ("http".equalsIgnoreCase(scheme)
                                || "https".equalsIgnoreCase(scheme))
                            && ALLOWED_DOMAINS.contains(host.toLowerCase())) {

                        // Safe: host and scheme validated against allowlist
                        return "redirect:" + uri.toString();
                    }
                } catch (URISyntaxException e) {
                    // fall through to safe default
                }

                // Fallback to a safe internal page on any failure or disallowed host
                return "redirect:/home";
            }
        }
        ```
      references:
        - https://find-sec-bugs.github.io/bugs.htm#UNVALIDATED_REDIRECT
        - https://cwe.mitre.org/data/definitions/601.html
      provenance: https://find-sec-bugs.github.io/bugs.htm#UNVALIDATED_REDIRECT
