        - rule: java/lib/spring/untrusted-data-source.yaml#spring-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/spring/unvalidated-redirect-sinks.yaml#spring-unvalidated-redirect-sinks
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$URL'

rules:
  - id: xss-in-servlet-app
    severity: ERROR
    message: >-
      Cross-site scripting (XSS): untrusted input is written to a Servlet response with text/html
      content type, so injected scripts will execute in the browser.
    metadata:
      cwe: CWE-79
      short-description: Cross-site scripting (XSS) in HTML response
      full-description: |-
        Cross-site scripting (XSS) occurs when untrusted input reaches a Servlet's response writer
        without proper HTML encoding, allowing an attacker to inject client-side code (usually JavaScript)
        into pages viewed by other users. Here the servlet explicitly sets the response content type
        to `text/html`, so the browser will render the response as HTML and execute any injected scripts.

        Vulnerable example:

        ```java
        import java.io.PrintWriter;
        import javax.servlet.annotation.WebServlet;
        import javax.servlet.http.HttpServlet;
        import javax.servlet.http.HttpServletRequest;
        import javax.servlet.http.HttpServletResponse;

        @WebServlet("/greet")
        public class GreetingServlet extends HttpServlet {
            @Override
            protected void doGet(HttpServletRequest request, HttpServletResponse response) throws java.io.IOException {
                response.setContentType("text/html;charset=UTF-8");
                PrintWriter out = response.getWriter();

                String name = request.getParameter("name"); // untrusted

                // VULNERABLE: tainted data reaches an HTML response unencoded
                out.println("<h1>Hello, " + name + "!</h1>");
            }
        }
        ```

        Safe example:

        ```java
        import java.io.PrintWriter;
        import javax.servlet.annotation.WebServlet;
        import javax.servlet.http.HttpServlet;
        import javax.servlet.http.HttpServletRequest;
        import javax.servlet.http.HttpServletResponse;
        import org.apache.commons.text.StringEscapeUtils;

        @WebServlet("/greet")
        public class GreetingServlet extends HttpServlet {
            @Override
            protected void doGet(HttpServletRequest request, HttpServletResponse response) throws java.io.IOException {
                response.setContentType("text/html;charset=UTF-8");
                PrintWriter out = response.getWriter();

                String name = request.getParameter("name");
                String safe = StringEscapeUtils.escapeHtml4(name == null ? "" : name);

                out.println("<h1>Hello, " + safe + "!</h1>");
            }
        }
        ```

        Key vulnerable patterns covered by this rule include `PrintWriter.print*` / `write` and
        `ServletOutputStream.print*` / `write` on responses whose content type is `text/html`,
        plus `HttpServletResponse.sendError(code, message)` and `JspWriter.write*` calls with tainted data.
      references:
        - https://owasp.org/www-community/attacks/xss/
      provenance:
        - https://github.com/semgrep/semgrep-rules/blob/develop/java/lang/security/audit/xss/no-direct-response-writer.yaml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/generic/servlet-xss-html-response-sinks.yaml#java-servlet-xss-html-response-sink
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

  - id: response-injection-in-servlet-app
    severity: NOTE
    message: >-
      Potential cross-site scripting (XSS): untrusted input is written to a Servlet response writer
      without HTML encoding.
    metadata:
      cwe: CWE-79
      short-description: Potential cross-site scripting (XSS)
      full-description: |-
        Cross-Site Scripting (XSS) is a class of vulnerabilities that allows an attacker to inject malicious
        client-side code (usually JavaScript) into web pages viewed by other users.
        In Java servlet applications, this typically occurs when untrusted input
        (e.g., request parameters, headers, form fields, query strings) is included in the HTTP response without proper output encoding.
        Attackers can leverage this to steal session cookies, perform actions on behalf of victims, modify page content,
        or conduct phishing attacks within the trusted site context.

        Make sure the response is actually rendered as HTML by the browser. This rule fires for any direct
        write of untrusted input to a Servlet response writer; if the response is served with a non-HTML
        content type (`application/json`, `text/plain`, an attachment, etc.) the impact is usually limited.
        When the content type is statically confirmed to be `text/html`, the ERROR-tier sibling rule
        `xss-in-servlet-app` reports the same flow at higher severity.

        **Vulnerable code sample**

        ```java
        import java.io.IOException;
        import java.io.PrintWriter;
        import javax.servlet.ServletException;
        import javax.servlet.annotation.WebServlet;
        import javax.servlet.http.HttpServlet;
        import javax.servlet.http.HttpServletRequest;
        import javax.servlet.http.HttpServletResponse;

        @WebServlet("/greet")
        public class GreetingServlet extends HttpServlet {

            @Override
            protected void doGet(HttpServletRequest request, HttpServletResponse response)
                    throws ServletException, IOException {

                response.setContentType("text/html;charset=UTF-8");
                PrintWriter out = response.getWriter();

                // Untrusted input taken directly from the request
                String name = request.getParameter("name");

                // VULNERABLE: Unencoded user input is directly embedded into HTML
                out.println("<html>");
                out.println("<head><title>Greeting</title></head>");
                out.println("<body>");
                out.println("<h1>Hello, " + name + "!</h1>"); // XSS if 'name' contains HTML/JS
                out.println("</body>");
                out.println("</html>");
            }
        }
        ```

        An attacker could call `/greet?name=<script>alert('XSS')</script>` and the script would execute in the victim's browser.


        To remediate this issue, always treat data from the client as untrusted and perform
        **context-appropriate output encoding** before including it in the response.
        For HTML content, escape characters such as `<`, `>`, `&`, `"`, `'` so they are rendered as text,
        not executed as code. Also validate and constrain inputs on the server side to expected formats
        (e.g., names, IDs) and avoid reflecting unnecessary user data.

        Below is a safer version using Apache Commons Text for HTML encoding:

        ```xml
        <!-- Maven dependency example -->
        <dependency>
            <groupId>org.apache.commons</groupId>
            <artifactId>commons-text</artifactId>
            <version>1.11.0</version>
        </dependency>
        ```

        ```java
        import java.io.IOException;
        import java.io.PrintWriter;
        import javax.servlet.ServletException;
        import javax.servlet.annotation.WebServlet;
        import javax.servlet.http.HttpServlet;
        import javax.servlet.http.HttpServletRequest;
        import javax.servlet.http.HttpServletResponse;
        import org.apache.commons.text.StringEscapeUtils;

        @WebServlet("/greet")
        public class GreetingServletSafe extends HttpServlet {

            @Override
            protected void doGet(HttpServletRequest request, HttpServletResponse response)
                    throws ServletException, IOException {

                response.setContentType("text/html;charset=UTF-8");
                PrintWriter out = response.getWriter();

                String name = request.getParameter("name");
                if (name == null) {
                    name = "";
                }

                // Encode untrusted input for HTML context
                String safeName = StringEscapeUtils.escapeHtml4(name);

                out.println("<html>");
                out.println("<head><title>Greeting</title></head>");
                out.println("<body>");
                out.println("<h1>Hello, " + safeName + "!</h1>");
                out.println("</body>");
                out.println("</html>");
            }
        }
        ```

        Key remediation steps:
        - Encode untrusted data according to the output context:
          - HTML body → HTML escape
          - HTML attributes → HTML attribute escape
          - JavaScript context → JavaScript escape
          - URL context → URL encode
        - Apply server-side validation and whitelisting of allowed characters/values.
        - Avoid constructing HTML/JavaScript by string concatenation where possible;
          use safe templating or tag libraries that handle encoding (e.g., JSP `<c:out>`).
        - Use security libraries and frameworks that provide standard encoding utilities.
      references:
        - https://owasp.org/www-community/attacks/xss/
      provenance:
        - https://github.com/semgrep/semgrep-rules/blob/develop/java/spring/security/injection/tainted-html-string.yaml
        - https://github.com/semgrep/semgrep-rules/blob/develop/java/lang/security/audit/xss/no-direct-response-writer.yaml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/generic/servlet-untrusted-data-source.yaml#java-servlet-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/generic/servlet-response-injection-sinks.yaml#java-servlet-response-injection-sink
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

  - id: xss-in-spring-app
    severity: ERROR
    message: >-
      Cross-site scripting (XSS): untrusted input flows into a Spring response with text/html
      content type, so injected scripts will execute in the browser.
    metadata:
      cwe: CWE-79
      short-description: Cross-site scripting (XSS) in HTML response
      full-description: |-
        Cross-site scripting (XSS) occurs when untrusted input is included in an HTML response without
        proper encoding, allowing an attacker to inject client-side code (usually JavaScript) into pages
        viewed by other users. In Spring applications, this happens when a handler writes untrusted input
        directly to `HttpServletResponse` with an HTML content type, or returns untrusted input from a
        handler annotated with `produces = "text/html"`. Here the response content type is statically
        confirmed to be `text/html`, so the browser will render the response as HTML and execute any
        injected scripts.

        Vulnerable example:

        ```java
        import org.springframework.web.bind.annotation.GetMapping;
        import org.springframework.web.bind.annotation.RequestParam;
        import org.springframework.web.bind.annotation.RestController;

        @RestController
        public class GreetingController {
            @GetMapping(value = "/greet", produces = "text/html")
            public String greet(@RequestParam String name) {
                // VULNERABLE: tainted data returned from a text/html handler unencoded
                return "<h1>Hello, " + name + "!</h1>";
            }
        }
        ```

        Safe example — encode before returning HTML:

        ```java
        import org.springframework.web.bind.annotation.GetMapping;
        import org.springframework.web.bind.annotation.RequestParam;
        import org.springframework.web.bind.annotation.RestController;
        import org.springframework.web.util.HtmlUtils;

        @RestController
        public class GreetingController {
            @GetMapping(value = "/greet", produces = "text/html")
            public String greet(@RequestParam String name) {
                return "<h1>Hello, " + HtmlUtils.htmlEscape(name) + "!</h1>";
            }
        }
        ```

        Safe example — return a typed DTO so Jackson serializes as JSON instead of HTML:

        ```java
        import org.springframework.http.ResponseEntity;
        import org.springframework.web.bind.annotation.GetMapping;
        import org.springframework.web.bind.annotation.RequestParam;
        import org.springframework.web.bind.annotation.RestController;

        @RestController
        public class GreetingController {
            public static class GreetingDto {
                public String name;
                public GreetingDto(String name) { this.name = name; }
            }

            @GetMapping("/greet")
            public ResponseEntity<GreetingDto> greet(@RequestParam(required = false, defaultValue = "") String name) {
                // Jackson serializes the DTO as application/json — the browser will not render it as HTML
                return ResponseEntity.ok(new GreetingDto(name));
            }
        }
        ```

        Key vulnerable patterns covered by this rule include controller returns from handlers with
        `produces = "text/html"`, direct writes to `HttpServletResponse.getWriter` / `getOutputStream`
        from a handler that sets a `text/html` content type, and `ResponseEntity` bodies with an
        HTML content type built from tainted strings.
      references:
        - https://owasp.org/www-community/attacks/xss/
      provenance:
        - https://github.com/semgrep/semgrep-rules/blob/develop/java/spring/security/injection/tainted-html-string.yaml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/spring/untrusted-data-source.yaml#spring-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/spring/spring-xss-html-response-sinks.yaml#spring-xss-html-response-sink
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

  - id: response-injection-in-spring-app
    severity: NOTE
    message: >-
      Potential cross-site scripting (XSS): untrusted input is rendered in a Spring view or response
      without HTML encoding.
    metadata:
      cwe: CWE-79
      short-description: Potential cross-site scripting (XSS)
      full-description: |-
        Cross-Site Scripting (XSS) is a class of vulnerabilities that allows an attacker to inject malicious
        client-side code (usually JavaScript) into web pages viewed by other users.
        In Spring MVC applications, this typically occurs when untrusted input (e.g., request parameters, form fields, query strings)
        is added to the model and then rendered in a view (JSP, Thymeleaf, etc.) without proper output encoding.
        If the view engine renders user data as raw HTML, an attacker can inject scripts that execute in the victim's browser
        in the context of your application (stealing cookies, hijacking sessions, modifying content, etc.).

        Make sure the response is actually rendered as HTML by the browser. This rule fires whenever
        untrusted input flows into a Spring response or view; if the endpoint serves the response as
        `application/json`, `text/plain`, or as an attachment, the impact is usually limited. When the
        content type is statically confirmed to be `text/html` (for example via `produces = "text/html"`
        or an explicit `setContentType`), the ERROR-tier sibling rule `xss-in-spring-app` reports the
        same flow at higher severity.

        **Vulnerable code sample**

        Controller:

        ```java
        import org.springframework.stereotype.Controller;
        import org.springframework.ui.Model;
        import org.springframework.web.bind.annotation.GetMapping;
        import org.springframework.web.bind.annotation.RequestParam;

        @Controller
        public class GreetingController {

            @GetMapping("/greet")
            public String greet(@RequestParam(required = false) String name, Model model) {
                model.addAttribute("name", name);
                return "greet"; // resolve to greet.html (Thymeleaf) or greet.jsp
            }
        }
        ```

        Thymeleaf view (`greet.html`) — **vulnerable**:

        ```html
        <!DOCTYPE html>
        <html xmlns:th="http://www.thymeleaf.org">
        <head>
            <title>Greeting</title>
        </head>
        <body>
            <!-- VULNERABLE: th:utext renders unescaped HTML/JS from user input -->
            <h1 th:utext="'Hello, ' + ${name} + '!'"></h1>
        </body>
        </html>
        ```

        If a user accesses `/greet?name=<script>alert('XSS')</script>`, the script will be inserted into the page and executed by the browser.

        (A similar issue occurs with JSP if you render `${param.name}` or `${name}` directly in the page without escaping,
        or if you use scriptlets and concatenate request parameters into HTML.)


        To remediate this issue, always treat data from the client as untrusted and ensure **context-appropriate output encoding**
        in your views. In Spring MVC:

        - Use the **escaping features of your view technology**:
          - Thymeleaf: `th:text` or `[[${...}]]` (escaped) instead of `th:utext` or `[(${...})]` (unescaped).
          - JSP: `<c:out value="${name}"/>` instead of printing `${name}` directly or using scriptlets.
        - Avoid disabling default escaping in template engines unless absolutely necessary, and never do so for raw user input.
        - Combine this with server-side validation that constrains inputs to expected formats.

        **Safer Thymeleaf example**

        Controller (same):

        ```java
        @Controller
        public class GreetingController {

            @GetMapping("/greet")
            public String greet(@RequestParam(required = false, defaultValue = "") String name, Model model) {
                model.addAttribute("name", name);
                return "greet";
            }
        }
        ```

        Thymeleaf view (`greet.html`) — **safe**:

        ```html
        <!DOCTYPE html>
        <html xmlns:th="http://www.thymeleaf.org">
        <head>
            <title>Greeting</title>
        </head>
        <body>
            <!-- SAFE: th:text escapes HTML special characters -->
            <h1 th:text="'Hello, ' + ${name} + '!'"></h1>
        </body>
        </html>
        ```

        Here, any `<`, `>`, `"`, `'`, and `&` characters in `name` are encoded as HTML entities (`&lt;`, `&gt;`, etc.),
        so injected script tags are rendered as text instead of executed.

        Additional recommended measures in Spring applications:
        - Use Spring Security and configure HTTP headers like `Content-Security-Policy` (CSP) to limit the impact of any XSS that might slip through.
        - Avoid building HTML/JavaScript via string concatenation in controllers; let the template engine handle rendering and escaping.
        - For JSON APIs (`@RestController`), ensure the front-end framework properly escapes data when inserting it into the DOM.
      references:
        - https://owasp.org/www-community/attacks/xss/
      provenance:
        - https://github.com/semgrep/semgrep-rules/blob/develop/java/spring/security/injection/tainted-html-string.yaml
        - https://github.com/semgrep/semgrep-rules/blob/develop/java/lang/security/audit/xss/no-direct-response-writer.yaml
    languages:
      - java
    mode: join
    join:
      refs:
        - rule: java/lib/spring/untrusted-data-source.yaml#spring-untrusted-data-source
          as: untrusted-data
        - rule: java/lib/spring/spring-response-injection-sinks.yaml#spring-response-injection-sink
          as: sink
      on:
        - 'untrusted-data.$UNTRUSTED -> sink.$UNTRUSTED'

  - id: xssrequestwrapper-is-insecure
    severity: WARNING
    options:
      disabled: pattern with concrete class name
    message: >-
      It looks like you're using an implementation of XSSRequestWrapper from dzone.
      (https://www.javacodegeeks.com/2012/07/anti-cross-site-scripting-xss-filter.html)
      The XSS filtering in this code is not secure and can be bypassed by malicious actors.
      It is recommended to use a stack that automatically escapes in your view or templates
      instead of filtering yourself.
    metadata:
      cwe:
        - CWE-79
      short-description: Insecure XSS filtering
      references:
        - https://www.javacodegeeks.com/2012/07/anti-cross-site-scripting-xss-filter.html
      provenance: https://find-sec-bugs.github.io/bugs.htm#XSS_REQUEST_WRAPPER
    languages:
